input.content:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  color-scheme: dark;
}

body {
  font-family: "Segoe UI", system-ui, -apple-system, sans-serif;
  background: #0b0f17;
  color: #e6e9ef;
  min-height: 100vh;
}

.page {
  max-width: 760px;
  margin: 0 auto;
  padding: 56px 20px 40px;
}

header h1 {
  font-size: 2rem;
  font-weight: 700;
  letter-spacing: -0.02em;
}

.tagline {
  margin-top: 8px;
  color: #8b93a5;
  font-size: 1rem;
}

.search-form {
  display: flex;
  gap: 10px;
  margin-top: 28px;
}

.search-form input {
  flex: 1;
  padding: 13px 16px;
  border-radius: 10px;
  border: 1px solid #26324a;
  background: #121826;
  color: #e6e9ef;
  font-size: 1rem;
  outline: none;
}

.search-form input:focus {
  border-color: #4f7cff;
}

.search-form button {
  padding: 13px 24px;
  border-radius: 10px;
  border: none;
  background: #4f7cff;
  color: #fff;
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
}

.search-form button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

.pipeline {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
  gap: 10px;
  margin-top: 28px;
}

.step {
  display: flex;
  align-items: center;
  gap: 9px;
  padding: 11px 14px;
  border-radius: 10px;
  border: 1px solid #1d2536;
  background: #101624;
  font-size: 0.88rem;
  color: #8b93a5;
}

.step .dot {
  width: 9px;
  height: 9px;
  border-radius: 50%;
  background: #2c3852;
  flex-shrink: 0;
}

.step.running {
  color: #d6dcff;
  border-color: #33427a;
}

.step.running .dot {
  background: #4f7cff;
  animation: pulse 1.1s ease-in-out infinite;
}

.step.done {
  color: #b9f0cf;
  border-color: #1e4a34;
}

.step.done .dot {
  background: #34d27b;
}

@keyframes pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.3;
  }
}

.error {
  margin-top: 24px;
  padding: 14px 16px;
  border-radius: 10px;
  border: 1px solid #5c2530;
  background: #1d1116;
  color: #ff9aa8;
}

.result {
  margin-top: 28px;
  padding: 26px;
  border-radius: 14px;
  border: 1px solid #1d2536;
  background: #101624;
}

.verdict-row {
  display: flex;
  align-items: center;
  gap: 22px;
  flex-wrap: wrap;
}

.verdict {
  font-size: 1.5rem;
  font-weight: 800;
  letter-spacing: 0.04em;
  padding: 9px 22px;
  border-radius: 10px;
}

.verdict.invest {
  background: #123524;
  color: #45e08f;
  border: 1px solid #1f5c3d;
}

.verdict.pass {
  background: #3a1520;
  color: #ff7a90;
  border: 1px solid #6b2638;
}

.confidence {
  flex: 1;
  min-width: 200px;
}

.confidence-label {
  font-size: 0.85rem;
  color: #8b93a5;
  margin-bottom: 7px;
}

.confidence-track {
  height: 8px;
  border-radius: 6px;
  background: #1d2536;
  overflow: hidden;
}

.confidence-fill {
  height: 100%;
  border-radius: 6px;
  background: linear-gradient(90deg, #4f7cff, #45e08f);
  transition: width 0.6s ease;
}

.thesis {
  margin-top: 22px;
  font-size: 1.05rem;
  line-height: 1.65;
}

.columns {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 22px;
  margin-top: 24px;
}

.columns h3 {
  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: #8b93a5;
  margin-bottom: 10px;
}

.columns ul {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 9px;
}

.columns li {
  padding-left: 16px;
  position: relative;
  font-size: 0.93rem;
  line-height: 1.5;
  color: #c6ccda;
}

.columns li::before {
  content: "";
  position: absolute;
  left: 0;
  top: 9px;
  width: 6px;
  height: 6px;
  border-radius: 50%;
}

.columns div:first-child li::before {
  background: #34d27b;
}

.columns div:last-child li::before {
  background: #ff7a90;
}

.horizon {
  margin-top: 22px;
  font-size: 0.93rem;
  color: #c6ccda;
}

.report {
  margin-top: 22px;
  border-top: 1px solid #1d2536;
  padding-top: 18px;
}

.report-toggle {
  background: none;
  border: none;
  color: #4f7cff;
  font-size: 0.9rem;
  cursor: pointer;
  padding: 0;
}

.report-body {
  margin-top: 14px;
  white-space: pre-wrap;
  font-family: inherit;
  font-size: 0.9rem;
  line-height: 1.65;
  color: #aeb6c6;
  max-height: 480px;
  overflow-y: auto;
}

footer {
  margin-top: 40px;
  text-align: center;
  font-size: 0.8rem;
  color: #566078;
}

@media (max-width: 560px) {
  .columns {
    grid-template-columns: 1fr;
  }
  .search-form {
    flex-direction: column;
  }
}

