  font-size: 0.85rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: #8b93a5;
  margin-bottom: 10px;
}

.columns ul {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 9px;
}

.columns li {
  padding-left: 16px;
  position: relative;
  font-size: 0.93rem;
  line-height: 1.5;
  color: #c6ccda;
}

.columns li::before {
  content: "";
  position: absolute;
  left: 0;
  top: 9px;
  width: 6px;
  height: 6px;
  border-radius: 50%;
}

.columns div:first-child li::before {
  background: #34d27b;
}

.columns div:last-child li::before {
  background: #ff7a90;
}

.horizon {
  margin-top: 22px;
  font-size: 0.93rem;
  color: #c6ccda;
}

.report {
  margin-top: 22px;
  border-top: 1px solid #1d2536;
  padding-top: 18px;
}

.report-toggle {
  background: none;
  border: none;
  color: #4f7cff;
  font-size: 0.9rem;
  cursor: pointer;
  padding: 0;
}

.report-body {
  margin-top: 14px;
  white-space: pre-wrap;
  font-family: inherit;
  font-size: 0.9rem;
  line-height: 1.65;
  color: #aeb6c6;
  max-height: 480px;
  overflow-y: auto;
}

footer {
  margin-top: 40px;
  text-align: center;
  font-size: 0.8rem;
  color: #566078;
}

@media (max-width: 560px) {
  .columns {
    grid-template-columns: 1fr;
  }
  .search-form {
    flex-direction: column;
  }
}

