import { z } from "zod";

const model = new ChatGroq({
  model: process.env.GROQ_MODEL || "llama-3.3-70b-versatile",
  temperature: 0.2,
  maxTokens: 1200,
  maxRetries: 0,
});

const search = new TavilySearch({ maxResults: 4 });

async function withRateLimitRetry(fn) {
  for (let attempt = 0; ; attempt++) {
    try {
      return await fn();
    } catch (err) {
      const message = err?.message || "";
      if (attempt >= 2 || !message.includes("rate_limit_exceeded")) throw err;
      const match = /try again in ([0-9.]+)s/.exec(message);
      const waitMs = match ? Math.ceil(parseFloat(match[1]) * 1000) + 500 : 20000;
      await new Promise((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

const decisionSchema = z.object({
  verdict: z.enum(["INVEST", "PASS"]),
  confidence: z.number().min(0).max(100),
  thesis: z.string(),
  strengths: z.array(z.string()).min(2).max(5),
  risks: z.array(z.string()).min(2).max(5),
  horizon: z.string(),
});

const ResearchState = Annotation.Root({
  company: Annotation(),
  profile: Annotation(),
  financials: Annotation(),
  news: Annotation(),
  competition: Annotation(),
  analysis: Annotation(),
  decision: Annotation(),
});

async function runSearch(query) {
  const response = await search.invoke({ query });
  const parsed = typeof response === "string" ? JSON.parse(response) : response;
  if (!parsed || !Array.isArray(parsed.results)) {
    throw new Error("web search failed, check your TAVILY_API_KEY");
  }
  const results = parsed.results;
  if (!results.length) return "No results found.";
  return results
    .map((r) => `Source: ${r.title} (${r.url})\n${(r.content || "").slice(0, 600)}`)
    .join("\n\n");
}

