toolUseResult.content:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  color-scheme: dark;
  --bg: #05080f;
  --surface: #0b111f;
  --surface-2: #0f1728;
  --border: #1a2338;
  --border-strong: #26324e;
  --text: #e8ecf4;
  --muted: #8a94ab;
  --faint: #59637b;
  --green: #2fe6a7;
  --green-dim: #123527;
  --blue: #5b8cff;
  --red: #ff7a90;
  --red-dim: #38141f;
  --grad: linear-gradient(100deg, #5b8cff, #2fe6a7);
}

body {
  font-family: "Inter", system-ui, -apple-system, sans-serif;
  background: var(--bg);
  background-image: radial-gradient(
      900px 480px at 70% -10%,
      rgba(91, 140, 255, 0.14),
      transparent 60%
    ),
    radial-gradient(
      700px 420px at 10% 0%,
      rgba(47, 230, 167, 0.08),
      transparent 55%
    );
  background-repeat: no-repeat;
  color: var(--text);
  min-height: 100vh;
  -webkit-font-smoothing: antialiased;
}

h1,
h2,
h3,
.brand,
.stat-value {
  font-family: "Space Grotesk", "Inter", sans-serif;
}

.shell {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

.navbar {
  position: sticky;
  top: 0;
  z-index: 20;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 14px;
  max-width: 1020px;
  width: 100%;
  margin: 0 auto;
  padding: 16px 24px;
  backdrop-filter: blur(14px);
  background: rgba(5, 8, 15, 0.72);
  border-bottom: 1px solid rgba(26, 35, 56, 0.6);
}

.brand {
  display: flex;
  align-items: center;
  gap: 10px;
  font-size: 1.08rem;
  font-weight: 700;
  letter-spacing: -0.02em;
  color: var(--text);
  text-decoration: none;
}

.brand-mark {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 30px;
  height: 30px;
  border-radius: 9px;
  background: var(--grad);
  color: #04121c;
  font-size: 0.78rem;
  font-weight: 700;
}

.brand-accent {
  color: var(--green);
}

.nav-links {
  display: flex;
  gap: 2px;
}

.nav-links a {
  color: var(--muted);
  text-decoration: none;
  font-size: 0.9rem;
  font-weight: 500;
  padding: 8px 14px;
  border-radius: 9px;
  transition: color 0.15s, background 0.15s;
}

.nav-links a:hover {
  color: var(--text);
}

.nav-links a.active {
  color: var(--text);
  background: rgba(26, 35, 56, 0.55);
}

.nav-cta {
  padding: 9px 18px;
  border-radius: 9px;
  background: var(--grad);
  color: #04121c;
  font-size: 0.88rem;
  font-weight: 600;
  text-decoration: none;
  white-space: nowrap;
}

.nav-cta:hover {
  filter: brightness(1.08);
}

.page {
  flex: 1;
  max-width: 860px;
  width: 100%;
  margin: 0 auto;
  padding: 40px 24px 56px;
}

header h2 {
  font-size: 1.8rem;
  font-weight: 700;
  letter-spacing: -0.02em;
}

.tagline {
  margin-top: 9px;
  color: var(--muted);
  font-size: 1rem;
}

.badge {
  display: inline-block;
  padding: 7px 15px;
  border-radius: 999px;
  border: 1px solid var(--border-strong);
  background: rgba(15, 23, 40, 0.7);
  color: var(--green);
  font-size: 0.78rem;
  font-weight: 600;
  letter-spacing: 0.09em;
  text-transform: uppercase;
}

.hero {
  text-align: center;
  padding: 52px 0 10px;
}

.hero h1 {
  margin-top: 22px;
  font-size: 3rem;
  font-weight: 700;
  letter-spacing: -0.03em;
  line-height: 1.12;
}

.grad {
  background: var(--grad);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
}

.hero p {
  margin: 20px auto 0;
  max-width: 560px;
  color: var(--muted);
  font-size: 1.1rem;
  line-height: 1.65;
}

.hero-actions {
  display: flex;
  justify-content: center;
  gap: 12px;
  margin-top: 32px;
}

.cta {
  display: inline-block;
  padding: 13px 28px;
  border-radius: 11px;
  background: var(--grad);
  color: #04121c;
  font-weight: 600;
  font-size: 0.98rem;
  text-decoration: none;
  transition: filter 0.15s;
}

.cta:hover {
  filter: brightness(1.08);
}

.cta.ghost {
  background: transparent;
  border: 1px solid var(--border-strong);
  color: var(--text);
}

.cta.ghost:hover {
  border-color: var(--blue);
  filter: none;
}

.preview {
  max-width: 560px;
  margin: 52px auto 0;
  border-radius: 16px;
  border: 1px solid var(--border);
  background: linear-gradient(180deg, var(--surface-2), var(--surface));
  box-shadow: 0 30px 80px rgba(0, 0, 0, 0.45);
  overflow: hidden;
  text-align: left;
}

.preview-bar {
  display: flex;
  align-items: center;
  gap: 7px;
  padding: 12px 16px;
  border-bottom: 1px solid var(--border);
}

.preview-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--border-strong);
}

.preview-title {
  margin-left: 8px;
  font-size: 0.78rem;
  color: var(--faint);
}

.preview-body {
  padding: 22px;
}

.preview-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 14px;
  margin-bottom: 18px;
}

.preview-company {
  display: block;
  font-size: 1.15rem;
  font-weight: 700;
}

.preview-time {
  font-size: 0.78rem;
  color: var(--faint);
}

.preview-thesis {
  margin-top: 18px;
  font-size: 0.9rem;
  line-height: 1.65;
  color: var(--muted);
}

.stats {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(170px, 1fr));
  gap: 12px;
  margin-top: 64px;
}

.stat {
  display: flex;
  flex-direction: column;
  gap: 7px;
  padding: 22px;
  border-radius: 14px;
  border: 1px solid var(--border);
  background: var(--surface);
  text-align: center;
}

.stat-value {
  font-size: 1.9rem;
  font-weight: 700;
  background: var(--grad);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
}

.stat-label {
  font-size: 0.83rem;
  line-height: 1.45;
  color: var(--muted);
}

.features {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(230px, 1fr));
  gap: 14px;
  margin-top: 56px;
}

.feature-card {
  padding: 26px 24px;
  border-radius: 16px;
  border: 1px solid var(--border);
  background: var(--surface);
  transition: border-color 0.2s, transform 0.2s;
}

.feature-card:hover {
  border-color: var(--border-strong);
  transform: translateY(-2px);
}

.feature-num {
  font-size: 0.8rem;
  font-weight: 700;
  color: var(--green);
  letter-spacing: 0.08em;
}

.feature-card h3 {
  margin-top: 12px;
  font-size: 1.04rem;
}

.feature-card p {
  margin-top: 10px;
  font-size: 0.9rem;
  line-height: 1.6;
  color: var(--muted);
}

.cta-band {
  margin-top: 64px;
  padding: 46px 30px;
  border-radius: 18px;
  border: 1px solid var(--border-strong);
  background: radial-gradient(
      500px 200px at 50% 0%,
      rgba(91, 140, 255, 0.14),
      transparent 70%
    ),
    var(--surface);
  text-align: center;
}

.cta-band h2 {
  font-size: 1.6rem;
  letter-spacing: -0.02em;
}

.cta-band p {
  margin: 12px 0 24px;
  color: var(--muted);
}

.search-form {
  display: flex;
  gap: 10px;
  margin-top: 30px;
}

.search-form input {
  flex: 1;
  padding: 14px 18px;
  border-radius: 12px;
  border: 1px solid var(--border-strong);
  background: var(--surface);
  color: var(--text);
  font-size: 1rem;
  font-family: inherit;
  outline: none;
  transition: border-color 0.15s;
}

.search-form input:focus {
  border-color: var(--blue);
}

.search-form button {
  padding: 14px 28px;
  border-radius: 12px;
  border: none;
  background: var(--grad);
  color: #04121c;
  font-size: 0.98rem;
  font-weight: 600;
  font-family: inherit;
  cursor: pointer;
}

.search-form button:disabled {
  opacity: 0.45;
  cursor: not-allowed;
}

.chips {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-wrap: wrap;
  margin-top: 14px;
}

.chips-label {
  font-size: 0.83rem;
  color: var(--faint);
}

.chip {
  padding: 7px 15px;
  border-radius: 999px;
  border: 1px solid var(--border);
  background: transparent;
  color: var(--muted);
  font-size: 0.85rem;
  font-family: inherit;
  cursor: pointer;
  transition: color 0.15s, border-color 0.15s;
}

.chip:hover {
  color: var(--text);
  border-color: var(--blue);
}

.pipeline {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(165px, 1fr));
  gap: 10px;
  margin-top: 30px;
}

.step {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 12px 15px;
  border-radius: 11px;
  border: 1px solid var(--border);
  background: var(--surface);
  font-size: 0.88rem;
  color: var(--muted);
}

.step .dot {
  width: 9px;
  height: 9px;
  border-radius: 50%;
  background: var(--border-strong);
  flex-shrink: 0;
}

.step.running {
  color: #d6dcff;
  border-color: rgba(91, 140, 255, 0.5);
}

.step.running .dot {
  background: var(--blue);
  animation: pulse 1.1s ease-in-out infinite;
}

.step.done {
  color: #b9f0cf;
  border-color: rgba(47, 230, 167, 0.35);
}

.step.done .dot {
  background: var(--green);
}

@keyframes pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.3;
  }
}

.error {
  margin-top: 26px;
  padding: 15px 18px;
  border-radius: 12px;
  border: 1px solid #5c2530;
  background: var(--red-dim);
  color: var(--red);
  font-size: 0.93rem;
}

.result {
  margin-top: 30px;
  padding: 30px;
  border-radius: 18px;
  border: 1px solid var(--border);
  background: linear-gradient(180deg, var(--surface-2), var(--surface));
}

.verdict-row {
  display: flex;
  align-items: center;
  gap: 24px;
  flex-wrap: wrap;
}

.verdict {
  font-size: 1.45rem;
  font-weight: 800;
  font-family: "Space Grotesk", sans-serif;
  letter-spacing: 0.05em;
  padding: 10px 24px;
  border-radius: 11px;
}

.verdict.small {
  font-size: 0.8rem;
  padding: 6px 14px;
}

.verdict.invest {
  background: var(--green-dim);
  color: var(--green);
  border: 1px solid rgba(47, 230, 167, 0.35);
}

.verdict.pass {
  background: var(--red-dim);
  color: var(--red);
  border: 1px solid rgba(255, 122, 144, 0.35);
}

.confidence {
  flex: 1;
  min-width: 200px;
}

.confidence-label {
  font-size: 0.85rem;
  color: var(--muted);
  margin-bottom: 8px;
}

.confidence-track {
  height: 8px;
  border-radius: 6px;
  background: var(--border);
  overflow: hidden;
}

.confidence-fill {
  height: 100%;
  border-radius: 6px;
  background: var(--grad);
  transition: width 0.6s ease;
}

.thesis {
