* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  color-scheme: dark;
}

body {
  font-family: "Segoe UI", system-ui, -apple-system, sans-serif;
  background: #0b0f17;
  color: #e6e9ef;
  min-height: 100vh;
}

.shell {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

.navbar {
